import { getStatusMeta } from "@/lib/status";
import type { Facility } from "@/lib/schema";

/**
 * Initial view centered on the contiguous United States.
 * Zoom 3.4 shows all 48 contiguous states comfortably.
 */
export const INITIAL_VIEW_STATE = {
  longitude: -98.5,
  latitude: 39.5,
  zoom: 3.4,
} as const;

/**
 * Precomputed pixel offsets for map markers to prevent WCAG 2.5.8 (target-size)
 * violations caused by geographically clustered markers overlapping at zoom 3.4.
 *
 * Generated by a force-separation simulation (max drift 22px) that pushes
 * overlapping pairs apart until all marker centres are ≥ 29px apart.
 * Re-run `scripts/compute-marker-offsets.py` after adding facilities or
 * updating coordinates.
 *
 * Facilities not listed here receive [0, 0] (no offset needed).
 */
const MARKER_OFFSETS: Record<string, [number, number]> = {
  "amazon-project-rainier-new-carlisle-in": [4, 2],
  "coreweave-kenilworth-nj": [3, -14],
  "coreweave-lancaster-pa": [20, 8],
  "culpeper-brandy-station-va": [-17, 12],
  "dc-blox-henrico-county-va": [8, 11],
  "equinix-ashburn-va": [0, -3],
  "google-the-dalles-or": [-1, -7],
  "homer-city-energy-campus-pa": [-1, -14],
  "meta-eagle-mountain-ut": [14, 2],
  "meta-hyperion-richland-parish-la": [-1, 1],
  "meta-prineville-or": [1, 7],
  "microsoft-mount-pleasant-wi": [-14, 11],
  "qts-eagle-mountain-ut": [-14, -2],
  "stargate-abilene-tx": [-10, 8],
  "stargate-lordstown-oh": [-12, 9],
  "stargate-milam-county-tx": [1, 2],
  "stargate-port-washington-wi": [0, -11],
  "stargate-saline-township-mi": [7, -11],
  "vantage-frontier-shackelford-county-tx": [9, -9],
  "xai-colossus-memphis-tn": [1, -1],
};

/**
 * Returns the precomputed pixel spread offset for a facility marker.
 * Falls back to [0, 0] for facilities that don't need offsetting.
 */
export function getMarkerOffset(facilityId: string): [number, number] {
  return MARKER_OFFSETS[facilityId] ?? [0, 0];
}

/**
 * OpenFreeMap positron style — free, no key required, low-saturation
 * for good marker contrast.
 *
 * TODO: theme-aware/dark basemap + self-hosted PMTiles later
 */
export const BASEMAP_STYLE_URL =
  "https://tiles.openfreemap.org/styles/positron";

/**
 * Builds a descriptive accessible label for a facility map marker.
 * Format: "Name, Operator — City, ST — Status — N MW [operational|planned]"
 * Capacity segment is omitted when capacityMw is not present.
 *
 * @example
 * buildMarkerLabel(colossus)
 * // "Colossus, xAI — Memphis, TN — Operational — 150 MW operational"
 */
export function buildMarkerLabel(f: Facility): string {
  const meta = getStatusMeta(f.status);
  const cityState = f.location.city
    ? `${f.location.city}, ${f.location.state}`
    : f.location.state;

  const parts: string[] = [
    `${f.name}, ${f.operator}`,
    cityState,
    meta.label,
  ];

  if (f.capacityMw?.operational !== undefined) {
    parts.push(`${f.capacityMw.operational} MW operational`);
  } else if (f.capacityMw?.planned !== undefined) {
    parts.push(`${f.capacityMw.planned} MW planned`);
  }

  return parts.join(" — ");
}
